member.summary:
Attribute to define a node type. Apply this to your node class.
Example:
[NodeType("my-node", "My Node", Category = NodeCategory.Function, Color = "#FFCC00")] public class MyNode : NodeBase { }

Attribute to define a property on a node. Apply this to properties of your node class for automatic binding.
Example:
[NodeProperty("topic", "Topic", Icon = "fa fa-tag")] public string Topic { get; set; } = "";

Fluent builder for creating node help text.
Example:
protected override NodeHelpText DefineHelp() => HelpBuilder.Create() .Summary("Injects a message into the flow.") .AddInput("payload", "string | number | object", "The payload to inject") .AddInput("topic", "string", "The message topic") .AddOutput("payload", "any", "The injected payload") .Details(@" This node can inject a message at regular intervals or when triggered. The payload can be configured as a timestamp, string, number, or JSON object. ") .AddReference("Node-RED Documentation", "https://nodered.org/docs/") .Build();

Base class for all custom nodes. Inherit from this class to create a new node type.

Example:

[NodeType("my-node", "My Node", Category = NodeCategory.Function)]
public class MyNode : NodeBase
{
    protected override Task OnInputAsync(NodeMessage msg, SendDelegate send, DoneDelegate done)
    {
        msg.Payload = "Hello from my node!";
        send(0, msg);
        done();
        return Task.CompletedTask;
    }
}

Fluent builder for creating node property definitions.
Example:
protected override List<NodePropertyDefinition> DefineProperties() => PropertyBuilder.Create() .AddText("topic", "Topic", icon: "fa fa-tag") .AddSelect("payloadType", "Payload Type", new[] { ("str", "String"), ("num", "Number"), ("json", "JSON") }) .AddNumber("timeout", "Timeout", min: 0, suffix: "seconds") .AddCheckbox("enabled", "Enabled", defaultValue: true) .AddCode("func", "Function", rows: 10) .Build();
